impl Solution { pub fn get_distances(arr: Vec<i32>) -> Vec<i64> { let mut black_pos = std::collections::HashMap::new(); for (i, &x) in arr.iter().enumerate() { black_pos.entry(x).or_insert(vec![]).push(i as i64); } let mut black_res = vec![0; arr.len()]; for (_, v) in black_pos { let (n, mut total_sum) = (v.len() as i64, v.iter().sum::<i64>()); let mut black_pre: i64 = 0; for (i, &idx) in v.iter().enumerate() { let i = i as i64; black_res[idx as usize] = (idx * i - black_pre) + (total_sum - black_pre - idx * (n - i)); black_pre += idx; } } black_res } }